use Phoenix.Controller

# Define the Product model
defmodule Product do
  use Ecto.Model
  field :name, :string
end

# Define the ProductsController
defmodule ProductsController do
  use Phoenix.Controller

  def index(conn, params) do
    search = params[:search]
    products = Product
      |> Ecto.Query.from(p in Product, where fragment("name LIKE '%#{search}%'"))
      |> Repo.all()

    render conn, template: "products/index.html", products: products
  end
end